/** Configuration for symbols on station plots */
interface SPSymbolConfig {
    type: 'symbol';

    /**
     * The position on the station plot at which to place the symbol
     */
    pos: SPPosition;

    /**
     * The color to use to draw the symbol
     * @default '#000000'
     */
    color?: string | ((symbol: SPSymbol | null, category: SPSymbolCategory) => string);

    /**
     * Whether to draw a halo (outline) around the string
     * @default true;
     */
    halo?: boolean;

    /**
     * The color to use for the halo (outline)
     * @default '#ffffff'
     */
    halo_color?: string;
}

/** Configuration for station plot sub-elements */
type SPConfig = SPNumberConfig | SPStringConfig | SPBarbConfig | SPSymbolConfig;

/**
 * Configuration for station data plots
 * @example
 * spconfig : SPDataConfig<'id' | 'tmpf' | 'wind' | 'skyc'> = {
 *      // Add a string to the station plot (like the station ID)
 *      id:   {type: 'string', pos: 'lr'},
 * 
 *      // Add a number to the station plot (like the temperature)
 *      tmpf: {type: 'number', pos: 'ul', color: '#cc0000', formatter: val => val === null ? '' : val.toFixed(0)},
 * 
 *      // Add a barb to the station plot
 *      wind: {type: 'barb', pos: 'c'},
 * 
 *      // Add a symbol to the station plot
 *      skyc: {type: 'symbol', pos: 'c'},
 * }
 */
type SPDataConfig<ObsFieldName extends string> = Record<ObsFieldName, SPConfig>;

/** Options for {@link StationPlot} components */
interface StationPlotOptions<ObsFieldName extends string> {
    config: SPDataConfig<ObsFieldName>, 
    /**
     * Thin factor at zoom level 1 for the station plots. Should be a power of 2.
     * @default 1
     */
    thin_fac?: number;

    /**
     * Font face to use for plotting text
     * @default 'Trebuchet MS'
     */
    font_face?: string;
    
    /**
     * Size of the font to use for the text
     * @default 12
     */
    font_size?: number;

    /**
     * URL template to use in retrieving the font data for the text. The default is to use the template from the map style.
     */
    font_url_template?: string;
}

const station_plot_opts_defaults: Required<StationPlotOptions<never>> = {
    config: {},
    thin_fac: 1,
    font_face: 'Trebuchet MS',
    font_size: 12,
    font_url_template: '',
};

interface StationPlotGLElems<GridType extends AutoZoomGrid, MapType extends MapLikeType> {
    map: MapType;
    gl: WebGLAnyRenderingContext;
    barb_components: Barbs<Float16Array, GridType, MapType>[];
}

function positionToAlignmentAndOffset(pos: SPPosition, off_size?: number) {
    off_size = off_size === undefined ? 10 : off_size;

    let ha: HorizontalAlign, va: VerticalAlign;
    let xoff: number, yoff: number;

    if(pos == 'll' || pos == 'cl' || pos == 'ul')      { ha = 'right'; xoff = -off_size; }
    else if (pos == 'lc' || pos == 'c' || pos == 'uc') { ha = 'center'; xoff = 0; }
    else                                               { ha = 'left'; xoff = off_size;}

    if (pos == 'll' || pos == 'lc' || pos == 'lr')     { va = 'top'; yoff = -off_size; }
    else if (pos == 'cl' || pos == 'c' || pos == 'cr') { va = 'middle'; yoff = 0; }
    else                                               { va = 'baseline'; yoff = off_size; }

    return {horizontal_align: ha, vertical_align: va, offset_x: xoff, offset_y: yoff};
}

type SPSymbolCategory = 'freezing_rain' | 'sleet' | 'snow' | 'rain' | 'blowing_dust' | 'thunder' | 'fog' | 'none';

function symbolCategory(symbol: SPSymbol) : SPSymbolCategory {
    const sym = symbol.toLowerCase();

    if (sym.includes('fzra') || (sym.includes('fz') && sym.includes('ra'))) return 'freezing_rain';
    if (sym.includes('pl')) return 'sleet';
    if (sym.includes('sn') || sym.includes('sg') || sym.includes('gs')) return 'snow';
    if (sym.includes('ra') || sym.includes('dz')) return 'rain';
    if (sym.includes('du') || sym.includes('ds') || sym.includes('ss') || sym.includes('blsa') || sym.includes('bldu') || sym.includes('blpy')) return 'blowing_dust';
    if (sym.includes('ts') || sym.includes('thdr')) return 'thunder';
    if (sym.includes('fg')) return 'fog';

    return 'none';
}

/** 
 * Station model plots for observed data
 * 
 * ## Grid Compatibility
 * - :white_check_mark: `PlateCarreeGrid`
 * - :white_check_mark: `PlateCarreeRotatedGrid`
 * - :white_check_mark: `LambertGrid`
 * - :white_check_mark: `UnstructuredGrid`
 * - :x:                `RadarSweepGrid`
 * - :x:                `Geostationary`
 * 
 * @example
 * // Specify how to set up the station plot
 * const station_plot_locs = {
 *     tmpf: {type: 'number', pos: 'ul', color: '#cc0000', formatter: val => val === null ? '' : val.toFixed(0)},
 *     dwpf: {type: 'number', pos: 'll', color: '#00aa00', formatter: val => val === null ? '' : val.toFixed(0)}, 
 *     wind: {type: 'barb', pos: 'c'},
 *     preswx: {type: 'symbol', pos: 'cl', color: '#ff00ff'},
 *     skyc: {type: 'symbol', pos: 'c'},
 * };
 * 
 * // Create the station plot
 * const station_plot = new StationPlot(obs_field, {config: station_plot_locs, thin_fac: 8, font_size: 14});
 */
class StationPlot<GridType extends AutoZoomGrid, MapType extends MapLikeType, ObsFieldName extends string> extends PlotComponent<MapType> {
    private field: RawObsField<GridType, ObsFieldName>;
    public readonly opts: Required<StationPlotOptions<ObsFieldName>>;
    private gl_elems: StationPlotGLElems<GridType, MapType> | null;
    private text_components: TextCollection[][] | null;

    /**
     * Create station plots
     * @param field - A field containing the observed data
     * @param opts  - Various options for the station plots
     */
    constructor(field: RawObsField<GridType, ObsFieldName>, opts: StationPlotOptions<ObsFieldName>) {
        super();

        this.field = field;
        this.opts = normalizeOptions(opts, station_plot_opts_defaults as Required<StationPlotOptions<ObsFieldName>>); // Is there a way to do this without invoking `as`?
        this.gl_elems = null;
        this.text_components = null;
    }

    /**
     * Update the data displayed as station plots
     * @param field - The new field to display as station plots
     */
    public async updateField(field: RawObsField<GridType, ObsFieldName>) {
        this.field = field;

        if (this.gl_elems === null) return;

        const map = this.gl_elems.map;
        const gl = this.gl_elems.gl;
        const barb_components = this.gl_elems.barb_components;

        const map_style = map.getStyle();

        const font_url_template = this.opts.font_url_template == '' ? map_style.glyphs : this.opts.font_url_template;
        if (font_url_template === undefined)
            throw "The map style doesn't have any glyph information. Please pass the font_url_template option to StationPlot";

        const font_url = font_url_template.replace('{fontstack}', this.opts.font_face);

        const coords = this.field.grid.getEarthCoords();
        const zoom = this.field.grid.getMinVisibleZoom(this.opts.thin_fac);

        let ibarb = 0;

        let sub_component_promises: Promise<TextCollection>[][] = [];

        Object.entries<SPConfig>(this.opts.config).forEach(async ([k_, config]) => {
            const k = k_ as ObsFieldName;

            if (config.type == 'number' || config.type == 'string') {
                const pos = config.pos;
                const color = config.color === undefined ? Color.fromHex('#000000') : Color.normalizeColor(config.color);
                const halo_color = config.halo_color === undefined ? Color.fromHex('#ffffff') : Color.normalizeColor(config.halo_color);
                const halo = config.halo === undefined ? true : config.halo;
                let cmap: ColorMap | null = null;

                let text_specs: TextSpec[];
                if (config.type == 'number') {
                    cmap = config.cmap === undefined ? null : config.cmap;
                    const comp = this.field.getScalar(k);
                    const formatter = config.formatter === undefined ? (val: number | null) => val === null ? 'null' : val.toString() : config.formatter;

                    text_specs = comp.map((v, i) => {
                        const spec: TextSpec = {
                            text: formatter(v),
                            lat: coords.lats[i],
                            lon: coords.lons[i],
                            min_zoom: zoom[i],
                        };

                        if (v !== null) 
                            spec.data_value = v;

                        return spec;
                    });
                }
                else {
                    const comp = this.field.getStrings(k);
                    text_specs = comp.map((v, i) => ({
                        text: v === null ? '' : v,
                        lat: coords.lats[i],
                        lon: coords.lons[i],
                        min_zoom: zoom[i],
                    }));
                }

                const tc_opts: TextCollectionOptions = {
                    ...positionToAlignmentAndOffset(pos),
                    font_size: this.opts.font_size, halo: halo, 
                    text_color: color, halo_color: halo_color,
                    cmap: cmap
                };

                sub_component_promises.push([TextCollection.make(gl, text_specs, font_url, tc_opts)]);
            }
            else if (config.type == 'barb') {
                const comp = this.field.getVector(k);
                const barb_comp = barb_components[ibarb++];
                barb_comp.updateField(comp);
            }
            else if (config.type == 'symbol') {
                const pos = config.pos;
                const color = config.color === undefined ? '#000000' : config.color;
                const halo_color = config.halo_color === undefined ? Color.fromHex('#ffffff') : Color.normalizeColor(config.halo_color);
                const halo = config.halo === undefined ? true : config.halo;

                const comp = this.field.getStrings(k) as (SPSymbol | null)[];
                const wxsym_font_url = font_url_template.replace('{fontstack}', 'wx_symbols');
                
                type TextSpecDataColor = {specs: TextSpec[], color: string};
                const text_spec_data: TextSpecDataColor[] = [];

                comp.forEach((v, i) => {
                    const v_cat: SPSymbolCategory = v === null ? 'none' : symbolCategory(v);
                    const text_color = typeof color === 'string' ? color : color(v, v_cat);
                    const text_spec_data_filtered = text_spec_data.filter(tsd => tsd.color == text_color)

                    let text_spec_color : TextSpecDataColor;
                    if (text_spec_data_filtered.length == 0) {
                        text_spec_color = {specs: [], color: text_color};
                        text_spec_data.push(text_spec_color);
                    }
                    else {
                        text_spec_color = text_spec_data_filtered[0];
                    }

                    text_spec_color.specs.push({
                        text: v === null ? '' : String.fromCharCode(SYMBOLS[v]),
                        lat: coords.lats[i],
                        lon: coords.lons[i],
                        min_zoom: zoom[i],
                    });
                });

                const promises: Promise<TextCollection>[] = []

                text_spec_data.forEach(tsd => {
                    const tc_opts: TextCollectionOptions = {
                        ...positionToAlignmentAndOffset(pos),
                        font_size: this.opts.font_size, halo: halo, 
                        text_color: Color.normalizeColor(tsd.color), halo_color: halo_color,
                    };

                    if (tc_opts.offset_x !== undefined) tc_opts.offset_x -= 3;

                    promises.push(TextCollection.make(gl, tsd.specs, wxsym_font_url, tc_opts));
                });

                sub_component_promises.push(promises);
            }
            else {
                throw `Unknown station plot configuration type ${(config as any).type}`;
            }
        });

        this.text_components = await Promise.all(sub_component_promises.map(p => Promise.all(p)));
        map.triggerRepaint();
    }

    /** @internal */
    public async onAdd(map: MapType, gl: WebGLAnyRenderingContext) {
        const barb_promises = Object.entries<SPConfig>(this.opts.config).map(async ([k_, config]) => {
            const k = k_ as ObsFieldName;
            if (config.type == 'barb') {
                const comp = this.field.getVector(k);

                const color = config.color === undefined ? '#000000' : config.color;
                const barb_size = config.barb_size_multipler === undefined ? 1 : config.barb_size_multipler;
                const barb_comp = new Barbs<Float16Array, GridType, MapType>(comp, {thin_fac: this.opts.thin_fac, color: color, barb_size_multiplier: barb_size});
                await barb_comp.onAdd(map, gl);
                return barb_comp;
            }
        });

        type BarbComponent = Barbs<Float16Array, GridType, MapType>;
        const barb_components = (await Promise.all(barb_promises)).filter((c: BarbComponent | undefined) : c is BarbComponent => c !== undefined);

        this.gl_elems = {
            map: map, gl: gl, barb_components: barb_components
        }

        this.updateField(this.field);
    }

    /** @internal */
    public render(gl: WebGLAnyRenderingContext, arg: RenderMethodArg) {
        if (this.gl_elems === null || this.text_components === null) return;

        const gl_elems = this.gl_elems;

        const text_components = this.text_components;
        const barb_components = this.gl_elems.barb_components;

        const map_width = gl_elems.map.getCanvas().width;
        const map_height = gl_elems.map.getCanvas().height;
        const map_zoom = gl_elems.map.getZoom();

        let itext = 0, ibarb = 0;
        Object.values<SPConfig>(this.opts.config).forEach((comp, idx) => {
            if (comp.type == 'barb') {
                barb_components[ibarb++].render(gl, arg);
            }
            else {
                text_components[itext++].forEach(tc => tc.render(gl, arg, [map_width, map_height], map_zoom));
            }
        });
    }
}

export default StationPlot;
export type {StationPlotOptions, SPPosition, SPNumberConfig, SPStringConfig, SPBarbConfig, SPSymbolConfig, SPConfig, SPDataConfig, SPSymbol};